import './Divider.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../helpers/classnames';
import type { DividerProps } from './Divider.types';

export const Divider: FC<DividerProps> = ({ className, type = 'horizontal', isDecorative, ...props }) => {
	const baseClass = classNames('dsb_divider', `dsb_divider--${type}`, className);

	return isDecorative ? (
		<div data-testid="Divider" aria-hidden="true" {...props} className={baseClass} />
	) : (
		<hr data-testid="Divider" role="separator" {...props} className={baseClass} />
	);
};
